import { getContext, setContext } from 'svelte';
export class AccordionManager {
    multiple;
    size;
    borderless;
    joined;
    activeItems = $state(new Set());
    constructor(multiple, size, borderless, joined) {
        this.multiple = multiple;
        this.size = size;
        this.borderless = borderless;
        this.joined = joined;
    }
    toggleItem(id) {
        if (this.multiple) {
            const newSet = new Set(this.activeItems);
            if (newSet.has(id)) {
                newSet.delete(id);
            }
            else {
                newSet.add(id);
            }
            this.activeItems = newSet;
        }
        else {
            this.activeItems = new Set(this.activeItems.has(id) ? [] : [id]);
        }
    }
    isItemActive(id) {
        return this.activeItems.has(id);
    }
}
const ACCORDION_MANAGER_KEY = 'atom-forge:accordion-manager';
export function createAccordionManager(multiple, size, borderless, joined) {
    const manager = new AccordionManager(multiple, size, borderless, joined);
    setAccordionManager(manager);
    return manager;
}
export const getAccordionManager = () => getContext(ACCORDION_MANAGER_KEY);
export const setAccordionManager = (manager) => setContext(ACCORDION_MANAGER_KEY, manager);
